const now = new Date();
const month = now.getMonth() + 1;
const seasons = { 12:0,1:0,2:0, 3:1,4:1,5:1, 6:2,7:2,8:2, 9:3,10:3,11:3 };
const seasonNames = ['Winter','Spring','Summer','Fall'];
const season = seasonNames[seasons[month]];
const services = ['Lawn Mowing','Fertilization','Aeration','Weeding','Mulching','Garden Bed Care','Bush Trimming','Spring Cleanup','Fall Cleanup','Leaf Removal','Gutter Cleaning','Snow Removal'];
const types = ['before_after','tip','testimonial','seasonal_promo','behind_the_scenes','educational'];
const posts = [];
for (let d = 0; d < 7; d++) {
  const postDate = new Date(Date.now() + (d+1)*24*60*60*1000);
  const service = services[d % services.length];
  const type = types[d % types.length];
  const captions = {
    before_after: `Amazing ${service} transformation in Madison! 🌿 Before & After. Your yard could look like this — call (608) 535-6057 #TotalGuard #MadisonWI #${service.replace(/ /g,'')}`,
    tip: `💡 ${season} tip: ${service} done right keeps your yard healthy all season. TotalGuard crew is ready! #LawnCare #Madison`,
    testimonial: `⭐⭐⭐⭐⭐ Another happy TotalGuard customer in Madison! Same crew, same day, every week. Book at tgyardcare.com`,
    seasonal_promo: `🌱 ${season} special: Get your ${service} booked before the rush! Limited spots — tgyardcare.com #MadisonWI`,
    behind_the_scenes: `A day in the life of your TotalGuard crew! Early mornings, great results 💪 #YardCare #MadisonWI`,
    educational: `Did you know? ${service} at the right time makes a huge difference for your lawn. Ask TotalGuard! (608) 535-6057`
  };
  posts.push({ content: captions[type], type, service, scheduled_for: postDate.toISOString(), status: 'draft', platform: 'facebook', season });
}
return posts.map(p => ({ json: p }));
